function parseAll(html){ const posts=[]; const blocks=String(html).split('tgme_widget_message_wrap'); for(const b of blocks){ const dm=b.match(/data-post="([^"]+)"/); if(!dm) continue; const parts=dm[1].split('/'); const ch=parts[0]; const id=parseInt(parts[1]||'',10); if(!ch||!id) continue; const tm=b.match(/datetime="([^"]+)"/); const date=tm?tm[1]:''; const txm=b.match(/tgme_widget_message_text[^>]*>([\s\S]*?)</div>/); const rawtext=txm?txm[1]:''; const text=decode(rawtext); const hrefs=[]; let hm; const re=/href="([^"]+)"/g; while((hm=re.exec(rawtext))){ const u=hm[1]; if(/^https?:/i.test(u)) hrefs.push(u); } const urlsInText=(text.match(/https?://[^\s)\]]+/g)||[]); const links=Array.from(new Set(hrefs.concat(urlsInText))); const hasAttach=/tgme_widget_message_(photo|video|document|voice|roundvideo)/.test(b); posts.push({ id, channel:ch, date, text, links, hasAttach, link:'https://t.me/'+ch+'/'+id }); } return posts; }
function isFileDoc(u){ return /\.(pdf|xlsx?|docx?|pptx?|csv)(\?|#|$)/i.test(u) || /(docs|drive|sheets)\.google\.com/i.test(u); }
const chMap={}; for(const c of $('Активные каналы').all()){ chMap[c.json.channel]={ last_id:Number(c.json.last_id)||0, category:c.json.category||'' }; }
const out=[]; for(const it of $input.all()){ const html=it.json&&it.json.data; if(typeof html!=='string') continue; for(const p of parseAll(html)){ const meta=chMap[p.channel]||{last_id:0,category:''}; if(p.id>meta.last_id){ const fdocs=(p.links||[]).filter(isFileDoc); let fl=fdocs.join(' | '); if(p.hasAttach) fl=(fl?fl+' | ':'')+'[вложение в Telegram]'; out.push({ json:{ channel:p.channel, category:meta.category, post_id:p.id, date:p.date, post_link:p.link, file_links:fl, text:p.text, links:p.links, hasAttach:p.hasAttach } }); } } } return out;

function isFileDoc(u){ return /\.(pdf|xlsx?|docx?|pptx?|csv)(\?|#|$)/i.test(u) || /(docs|drive|sheets)\.google\.com/i.test(u); }
function passFilter(p){ if(p.hasAttach) return true; if(p.links && p.links.length) return true; const reL=/\b(seo|ai|llm|gpt|claude|guide|tool|case|release|schema|ahrefs|gsc|api)\b/i; const reC=/(серп|выдач|ссылк|индекс|краул|нейросет|нейронк|диффуз|кейс|гайд|инструкци|инструмент|сервис|релиз|обновлени|выпуст|рекоменду|советую|подборк|core web vitals|midjourney)/i; return reL.test(p.text||'') || reC.test(p.text||''); }
return $input.all().filter(it=> passFilter({ text:it.json.text, links:it.json.links, hasAttach:it.json.hasAttach }));

const SYSTEM = 'Ты строгий фильтр постов из Telegram для рабочей базы Антона по SEO, iGaming и AI-автоматизации. По умолчанию useful=false. Ставь useful=true ТОЛЬКО если пост реально применим в работе, то есть это одно из: конкретный инструмент или сервис который можно взять и использовать (с названием); рабочая методика или прием который можно повторить; разбор кейса с цифрами и понятным выводом что сработало; конкретное изменение в SEO (алгоритмы, выдача, индексация) или в правилах площадок и партнерок, влияющее на работу. Жестко отсекай useful=false: новости про релизы и драму ИИ-моделей, посты в духе лучше или хуже, обзоры и сравнения видео и картиночных моделей, общую индустриальную болтовню, аналитику без прикладного действия, анонсы, рекламу, продажу курсов, вакансии, розыгрыши, мемы. Тип рынок ставь только под конкретные цифры или изменения правил. Верни строго JSON-массив, без markdown и пояснений. Для каждого поста объект: {"i": индекс из входа, "useful": true или false, "type": если useful один из инструмент, методика, кейс, рынок, материал, "summary": если useful СТРОГО одна короткая строка на русском, максимум 18 слов, одно предложение, без точки с запятой и без длинных перечислений, сначала название инструмента или что изменилось, потом одним куском что делать}. Для бесполезных хватит {"i":N,"useful":false}. Пиши по-русски, без буквы е с точками и без длинного тире.';
const GROUP=10;
const rows=$input.all().map(i=>i.json);
const out=[];
for(let s=0;s<rows.length;s+=GROUP){ const chunk=rows.slice(s,s+GROUP); const posts=chunk.map((r,idx)=>({ i:idx, channel:r.channel, category:r.category, text:(r.text&&String(r.text).trim())?String(r.text).slice(0,1500):'(пустой пост, только медиа)' })); out.push({ json:{ rows:chunk, body:{ model:'claude-sonnet-4-6', max_tokens:3000, system:SYSTEM, messages:[{ role:'user', content:'Посты:\n'+JSON.stringify(posts) }] } } }); }
return out;

function clean(s){ return String(s==null?'':s).replace(/ё/g,'е').replace(/Ё/g,'Е').replace(/\s*[—–]\s*/g,', '); }
const ctx=$('Собрать батч Claude').all();
const items=$input.all();
const out=[];
for(let k=0;k<items.length;k++){ const rows=(ctx[k]&&ctx[k].json.rows)?ctx[k].json.rows:[]; const r=items[k].json; let txt=''; try{ txt=r&&r.content&&r.content[0]&&r.content[0].text?r.content[0].text:''; }catch(e){} if(!txt) continue; let arr=null; try{ const cl=String(txt).replace(/```json/gi,'').replace(/```/g,'').trim(); const a=cl.indexOf('['); const b=cl.lastIndexOf(']'); arr=JSON.parse(a>=0&&b>=0?cl.slice(a,b+1):cl); }catch(e){ continue; } if(!Array.isArray(arr)) continue; for(const v of arr){ if(!v||v.useful!==true) continue; const row=rows[v.i]; if(!row) continue; out.push({ json:{ date:row.date||'', category:row.category||'', type:clean(String(v.type||'')), channel:row.channel||'', summary:clean(String(v.summary||'')), post_link:row.post_link||'', file_links:row.file_links||'' } }); } }
return out;

function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function clean(s){ return String(s==null?'':s).replace(/ё/g,'е').replace(/Ё/g,'Е').replace(/\s*[—–]\s*/g,', '); }
function shorten(s){ s=clean(s).replace(/\s+/g,' ').trim(); const dot=s.search(/[.!?]\s/); if(dot>40) s=s.slice(0,dot+1); if(s.length>140){ let t=s.slice(0,140); const sp=t.lastIndexOf(' '); if(sp>0) t=t.slice(0,sp); s=t.replace(/[\s.,;:]+$/,'')+'…'; } return s; }
function pointBody(r){ let s=shorten(r.summary); let head=s, tail=''; const ci=s.search(/[,:]/); if(ci>0){ head=s.slice(0,ci).trim(); tail=s.slice(ci+1).trim(); } else { const parts=s.split(' '); if(parts.length>5){ head=parts.slice(0,4).join(' '); tail=parts.slice(4).join(' '); } } let ln='<b>'+esc(head)+'</b>'; if(tail) ln+=' '+esc(tail); if(r.post_link) ln+=' '+esc(r.post_link); return ln; }
const SINCE = Date.now() - 24*60*60*1000;
let rows=$input.all().map(i=>i.json).filter(r=>{ if(!r||!r.summary) return false; const d=Date.parse(r.date); return isFinite(d)&&d>=SINCE; });
rows.forEach(r=>{ r._t=Date.parse(r.date)||0; });
const cats=[['iGaming','🎰'],['AI','🤖'],['SEO','🔍']];
const typeOrder=['инструмент','методика','кейс','рынок','материал'];
const MAXPERCAT=8; const MSGLIMIT=4000;
const out=[];
for(const ce of cats){ const cat=ce[0], emoji=ce[1]; let list=rows.filter(r=> (['iGaming','AI','SEO'].indexOf(r.category)>=0?r.category:'AI')===cat); if(!list.length) continue; list.sort((a,b)=> b._t-a._t); const total=list.length; const top=list.slice(0,MAXPERCAT); const extra=total-top.length; const byType={}; for(const r of top){ const t=(r.type&&String(r.type).trim())?clean(String(r.type).trim()):'прочее'; (byType[t]=byType[t]||[]).push(r); } const seen=[]; for(const t of typeOrder){ if(byType[t]) seen.push(t); } for(const t of Object.keys(byType)){ if(typeOrder.indexOf(t)<0) seen.push(t); } const segs=[]; let n=0; for(const t of seen){ segs.push(''); segs.push('<b>'+esc(t)+'</b>'); for(const r of byType[t]){ n++; segs.push(n+'. '+pointBody(r)); } } if(extra>0){ segs.push(''); segs.push('<i>и еще '+extra+'</i>'); } const headerLine=emoji+' <b>'+esc(cat)+'</b>'; let buf=headerLine; for(const seg of segs){ if((buf+'\n'+seg).length>MSGLIMIT){ out.push({ json:{ text:buf } }); buf=headerLine; } buf+='\n'+seg; } out.push({ json:{ text:buf } }); }
if(!out.length) out.push({ json:{ text:'🤖 <b>InfoScout</b>\nЗа последние сутки полезного не найдено.' } });
return out;
